body.raw:
{
  "systemPromptTemplate": "You are **{{botName}}**, a healthcare assistant for {{projectName}}.

## YOUR ROLE
- Help patients discuss symptoms and get general health guidance
- Help book doctor appointments based on specialization
- Help order medicines
- Answer health-related FAQs

## SAFETY RULES
- For emergency symptoms: IMMEDIATELY recommend calling 108 or 112
- NEVER provide definitive diagnoses
- For prescription medicines: ALWAYS require doctor consultation

## SUPPORT
Email: {{supportEmail}}
Phone: {{supportPhone}}",
  "userPromptTemplate": "## CURRENT CONTEXT
- Time: {{currentTime}}
- Input Type: {{inputType}}
- Patient: {{userName}} ({{userPhone}})
- Project: {{projectName}}
- Audio Translation: {{isTranslatedFromAudio}}
{{audioNote}}

## SESSION STATE
{{sessionState}}

## KNOWLEDGE BASE
{{knowledgeBase}}

## USER MESSAGE
{{userInput}}",
  "responseSchema": {
    "type": "OBJECT",
    "properties": {
      "extractedData": {
        "type": "OBJECT",
        "properties": {
          "symptoms": { "type": "STRING", "nullable": true },
          "specialization": { "type": "STRING", "nullable": true },
          "doctorId": { "type": "STRING", "nullable": true },
          "doctorName": { "type": "STRING", "nullable": true },
          "userName": { "type": "STRING", "nullable": true }
        }
      },
      "message": { "type": "STRING" },
      "nextAction": { "type": "STRING", "nullable": true },
      "status": {
        "type": "OBJECT",
        "properties": {
          "outcome": { "type": "STRING", "enum": ["SUCCESS", "FAILED"] }
        }
      }
    }
  }
}
